sql:
SELECT athlete_id, COUNT(DISTINCT event_id) AS event_count
FROM performances
GROUP BY athlete_id;

SELECT athlete_id, event_id
FROM performances
WHERE meet_id = (SELECT meet_id FROM meets WHERE meet_name = 'John Hay Pennsylvania Distance Festival presented by BMRC');

external_knowledge:
- A relay leg is considered "completed" if a leg time is recorded; 
- The fastest times are those with the smallest numerical values; 
- The purpose of this query is to rank the performance of athletes in relay events based on their speed.

sql:
SELECT meet_id, COUNT(admin_id) AS admin_count
FROM meet_administrators
GROUP BY meet_id;

SELECT admin_name, admin_email
FROM meet_administrators
ORDER BY admin_name ASC;

SELECT result_time
FROM event_results
WHERE result_id = 0;
